import boto3
from PIL import Image
import io
import logging

# Initialize clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')
cloudwatch_logs = boto3.client('logs')

def lambda_handler(event, context):
    # Log to CloudWatch
    logger = logging.getLogger()
    logger.setLevel(logging.INFO)
    
    bucket_name = event['Records'][0]['s3']['bucket']['name']
    key = event['Records'][0]['s3']['object']['key']
    
    try:
        # Read the image from S3
        response = s3_client.get_object(Bucket=bucket_name, Key=key)
        image_content = response['Body'].read()
        
        # Process the image (example: resize)
        image = Image.open(io.BytesIO(image_content))
        resized_image = image.resize((100, 100), Image.ANTIALIAS)
        
        # Save the processed image to a buffer
        img_buffer = io.BytesIO()
        resized_image.save(img_buffer, format=image.format)
        img_buffer.seek(0)
        
        # Write the processed image back to S3
        output_key = f'processed/{key}'
        s3_client.put_object(Bucket=bucket_name, Key=output_key, Body=img_buffer)
        
        # Send notification via SNS
        sns_arn = 'arn:aws:sns:REGION:ACCOUNT_ID:TopicName'
        message = f"Image processed successfully and saved to {output_key}"
        sns_client.publish(TopicArn=sns_arn, Message=message)
        
        logger.info(f"Processed image {key} and sent notification.")
    
    except Exception as e:
        logger.error(f"Error processing image {key}: {str(e)}")
        raise

